import React from 'react';
import { Filter, X } from 'lucide-react';

const CourseFilters = ({ 
  activeFilter, 
  setActiveFilter, 
  priceRange, 
  setPriceRange, 
  ratingFilter, 
  setRatingFilter,
  showAdvanced,
  setShowAdvanced 
}) => {
  const categories = [
    { id: 'all', name: 'All Courses', count: 0 },
    { id: 'development', name: 'Development', count: 0 },
    { id: 'ai', name: 'AI & ML', count: 0 },
    { id: 'design', name: 'Design', count: 0 },
    { id: 'business', name: 'Business', count: 0 }
  ];

  const clearFilters = () => {
    setActiveFilter('all');
    setPriceRange([0, 200]);
    setRatingFilter(0);
    setShowAdvanced(false);
  };

  return (
    <div className="bg-white border-b border-gray-200 py-6">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex flex-wrap gap-2">
            {categories.map(category => (
              <button 
                key={category.id}
                onClick={() => setActiveFilter(category.id)}
                className={`px-4 py-2 rounded-xl text-sm font-medium transition-all duration-200 ${
                  activeFilter === category.id 
                    ? 'bg-gradient-to-r from-blue-600 to-purple-600 text-white shadow-lg transform scale-105' 
                    : 'text-gray-700 bg-gray-100 hover:bg-gray-200 hover:scale-105'
                }`}
              >
                {category.name}
              </button>
            ))}

            <button
              onClick={() => setShowAdvanced(!showAdvanced)}
              className="flex items-center px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-xl hover:bg-gray-200 transition-colors"
            >
              <Filter className="w-4 h-4 mr-2" />
              Advanced
            </button>
          </div>

          {(activeFilter !== 'all' || priceRange[1] !== 200 || ratingFilter > 0) && (
            <button
              onClick={clearFilters}
              className="flex items-center px-4 py-2 text-sm font-medium text-red-600 bg-red-50 rounded-xl hover:bg-red-100 transition-colors"
            >
              <X className="w-4 h-4 mr-2" />
              Clear Filters
            </button>
          )}
        </div>

        {showAdvanced && (
          <div className="mt-6 p-6 bg-gray-50 rounded-2xl border border-gray-200">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Price Range: ₹0 - ₹{priceRange[1]}
                </label>
                <input
                  type="range"
                  min="0"
                  max="200"
                  value={priceRange[1]}
                  onChange={(e) => setPriceRange([0, parseInt(e.target.value)])}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Minimum Rating</label>
                <select
                  value={ratingFilter}
                  onChange={(e) => setRatingFilter(parseFloat(e.target.value))}
                  className="w-full bg-white border border-gray-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                >
                  <option value={0}>Any Rating</option>
                  <option value={4.5}>4.5+ Stars</option>
                  <option value={4.0}>4.0+ Stars</option>
                  <option value={3.5}>3.5+ Stars</option>
                </select>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CourseFilters;
